const express = require('express');
const session = require('express-session');
const { Issuer, Strategy } = require('openid-client');
const jwt = require('jsonwebtoken');

const app = express();
app.use(session({
  secret: 'your-secret-key',
  resave: false,
  saveUninitialized: true
}));

const openidIssuerUrl = 'https://your-openid-provider.com';
const clientId = 'your-client-id';
const clientSecret = 'your-client-secret';
const redirectUri = 'http://localhost:3000/callback';

async function createClient() {
  const issuer = await Issuer.discover(openidIssuerUrl);
  const client = new issuer.Client({
    client_id: clientId,
    client_secret: clientSecret,
    redirect_uris: [redirectUri],
    response_types: ['code']
  });

  app.use(require('passport').initialize());
  app.use(require('passport').session());
  
  require('passport').use('oidc', new Strategy({ client }, (tokenset, userinfo, done) => {
    const claims = jwt.decode(tokenset.id_token);
    done(null, claims);
  }));

  require('passport').serializeUser((user, done) => {
    done(null, user);
  });

  require('passport').deserializeUser((obj, done) => {
    done(null, obj);
  });
}

createClient().then(() => {
  app.get('/login', (req, res, next) => {
    require('passport').authenticate('oidc')(req, res, next);
  });

  app.get('/callback', (req, res, next) => {
    require('passport').authenticate('oidc', {
      successRedirect: '/',
      failureRedirect: '/login'
    })(req, res, next);
  });

  app.get('/', (req, res) => {
    if (!req.isAuthenticated()) {
      return res.redirect('/login');
    }
    res.send(`Hello ${req.user.name}`);
  });

  app.listen(3000, () => {
    console.log('Server running on http://localhost:3000');
  });
}).catch(console.error);